sql:
SELECT COUNT(*) AS trial_count
FROM trials
WHERE trial_date = '2023-04-01';

SELECT pig_breed, AVG(pig_weight) AS average_weight
FROM pigs
GROUP BY pig_breed;

SELECT group_id, COUNT(DISTINCT test_day) AS test_day_count
FROM trials
GROUP BY group_id;

SELECT COUNT(DISTINCT T1.trapped_pig_uniq_id) AS unique_pigs_exposed
FROM trials T1
WHERE T1.trial_stimulus = 'SpecificStimulus';

SELECT group_name, AVG(group_size) AS avg_group_size
FROM groups
GROUP BY group_name;

SELECT COUNT(trial_id) AS total_trials
FROM trials
WHERE trial_environment = 'indoor';

SELECT AVG(test_subj_opens_testbox) AS average_pig_opens_testbox
FROM trials
WHERE trapped_before = 'Yes';
